import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { FaMapMarkedAlt, FaGlobeAsia, FaBook, FaChartLine, FaArrowRight, FaPlane, FaCompass, FaRoute, FaCalendarAlt, FaCheckCircle } from 'react-icons/fa';
import './LandingPage.css';

const features = [
  {
    icon: <FaMapMarkedAlt />,
    title: 'India Map Dashboard',
    desc: 'Interactive SVG map to track every state and union territory across India with real-time progress.'
  },
  {
    icon: <FaGlobeAsia />,
    title: 'World Map Explorer',
    desc: 'Pin countries across the globe, add visit dates & notes, and build your worldwide travel portfolio.'
  },
  {
    icon: <FaBook />,
    title: 'Destination Journal',
    desc: 'Log destinations within each state, mark favorites, and track your exploration by region.'
  },
  {
    icon: <FaChartLine />,
    title: 'Travel Analytics',
    desc: 'Beautiful donut charts, progress rings, and milestone badges that celebrate your adventures.'
  },
  {
    icon: <FaCalendarAlt />,
    title: 'Trip Planner',
    desc: 'Plan upcoming trips with dates, notes, and checklists. Never forget a travel detail again.'
  },
  {
    icon: <FaCheckCircle />,
    title: 'Milestone Badges',
    desc: 'Unlock achievements as you explore — from First Step to All India, every visit counts.'
  },
];

const stats = [
  { value: '36', label: 'States & UTs' },
  { value: '195+', label: 'Countries' },
  { value: '1000+', label: 'Destinations' },
];

export default function LandingPage() {
  const navigate = useNavigate();
  const [scrollY, setScrollY] = useState(0);
  const mapRef = useRef(null);

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) navigate('/dashboard');
  }, [navigate]);

  // Load the real world map SVG
  useEffect(() => {
    if (!mapRef.current) return;
    fetch('/WorldMap_SVG_Source.normalized.svg')
      .then(res => res.text())
      .then(svgContent => {
        if (!mapRef.current) return;
        mapRef.current.innerHTML = svgContent;
        const svg = mapRef.current.querySelector('svg');
        if (!svg) return;

        const W = 2754, H = 1398;
        svg.setAttribute('viewBox', `0 0 ${W} ${H}`);
        svg.removeAttribute('width');
        svg.removeAttribute('height');
        svg.style.width = '100%';
        svg.style.height = '100%';
        svg.style.display = 'block';
        svg.setAttribute('preserveAspectRatio', 'xMidYMid meet');

        const styleEl = svg.querySelector('style');
        if (styleEl) styleEl.remove();

        svg.querySelectorAll('circle').forEach(c => c.setAttribute('opacity', '0'));

        svg.querySelectorAll('path').forEach(path => {
          path.setAttribute('fill', '#2a4a6b');
          path.setAttribute('stroke', '#1a3352');
          path.setAttribute('stroke-width', '0.5');
        });

        const visited = ['India', 'France', 'Australia', 'Brazil', 'Japan'];
        svg.querySelectorAll('g').forEach(g => {
          const title = g.querySelector('title');
          if (title && visited.some(v => title.textContent.includes(v))) {
            g.querySelectorAll('path').forEach(p => {
              p.setAttribute('fill', '#34d399');
              p.setAttribute('stroke', '#6ee7b7');
              p.setAttribute('stroke-width', '0.8');
            });
          }
        });

        // Animated flight arcs
        const ns = 'http://www.w3.org/2000/svg';
        const overlay = document.createElementNS(ns, 'g');
        const routes = [
          { x1: 0.53, y1: 0.30, x2: 0.72, y2: 0.40, color: '#3b82f6' },
          { x1: 0.72, y1: 0.40, x2: 0.87, y2: 0.33, color: '#8b5cf6' },
          { x1: 0.17, y1: 0.32, x2: 0.53, y2: 0.30, color: '#06b6d4' },
          { x1: 0.72, y1: 0.40, x2: 0.84, y2: 0.72, color: '#f59e0b' },
          { x1: 0.30, y1: 0.62, x2: 0.53, y2: 0.48, color: '#ec4899' },
        ];
        routes.forEach((r, i) => {
          const x1 = r.x1 * W, y1 = r.y1 * H, x2 = r.x2 * W, y2 = r.y2 * H;
          const mx = (x1 + x2) / 2, my = Math.min(y1, y2) - Math.abs(x2 - x1) * 0.18;

          const arc = document.createElementNS(ns, 'path');
          arc.setAttribute('d', `M${x1},${y1} Q${mx},${my} ${x2},${y2}`);
          arc.setAttribute('fill', 'none');
          arc.setAttribute('stroke', r.color);
          arc.setAttribute('stroke-width', '3');
          arc.setAttribute('opacity', '0.5');
          arc.setAttribute('stroke-dasharray', '12 8');
          const ad = document.createElementNS(ns, 'animate');
          ad.setAttribute('attributeName', 'stroke-dashoffset');
          ad.setAttribute('values', '0;-40');
          ad.setAttribute('dur', `${1.5 + i * 0.3}s`);
          ad.setAttribute('repeatCount', 'indefinite');
          arc.appendChild(ad);
          overlay.appendChild(arc);

          const dot = document.createElementNS(ns, 'circle');
          dot.setAttribute('r', '6');
          dot.setAttribute('fill', r.color);
          const am = document.createElementNS(ns, 'animateMotion');
          am.setAttribute('dur', `${3 + i * 0.4}s`);
          am.setAttribute('repeatCount', 'indefinite');
          am.setAttribute('path', `M${x1},${y1} Q${mx},${my} ${x2},${y2}`);
          dot.appendChild(am);
          overlay.appendChild(dot);

          [{ cx: x1, cy: y1 }, { cx: x2, cy: y2 }].forEach(pt => {
            const city = document.createElementNS(ns, 'circle');
            city.setAttribute('cx', pt.cx);
            city.setAttribute('cy', pt.cy);
            city.setAttribute('r', '6');
            city.setAttribute('fill', r.color);
            city.setAttribute('opacity', '0.8');
            const p = document.createElementNS(ns, 'animate');
            p.setAttribute('attributeName', 'r');
            p.setAttribute('values', '5;10;5');
            p.setAttribute('dur', '2s');
            p.setAttribute('repeatCount', 'indefinite');
            city.appendChild(p);
            overlay.appendChild(city);
          });
        });
        svg.appendChild(overlay);
      });
  }, []);

  useEffect(() => {
    const handleScroll = () => setScrollY(window.scrollY);
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <div className="landing">
      {/* Navigation */}
      <nav className={`landing-nav ${scrollY > 50 ? 'scrolled' : ''}`}>
        <div className="landing-nav-inner">
          <div className="landing-logo">
            <FaCompass className="landing-logo-icon" />
            <span>MyTravelGlimpse</span>
          </div>
          <div className="landing-nav-actions">
            <button className="nav-btn-ghost" onClick={() => navigate('/login')}>Log In</button>
            <button className="nav-btn-primary" onClick={() => navigate('/signup')}>
              Get Started <FaArrowRight />
            </button>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <section className="landing-hero">
        <div className="hero-bg-shapes">
          <div className="hero-shape hero-shape-1" />
          <div className="hero-shape hero-shape-2" />
          <div className="hero-shape hero-shape-3" />
        </div>
        <div className="hero-content">
          <div className="hero-badge">
            <FaPlane /> Your Personal Travel Companion
          </div>
          <h1 className="hero-title">
            Every Journey<br />
            <span className="hero-gradient-text">Deserves a Glimpse</span>
          </h1>
          <p className="hero-subtitle">
            Track visited states, pin countries on the world map, journal every destination,
            and watch your travel story unfold with beautiful maps and analytics.
          </p>
          <div className="hero-actions">
            <button className="hero-btn-primary" onClick={() => navigate('/signup')}>
              Start Your Map Free <FaArrowRight />
            </button>
            <button className="hero-btn-secondary" onClick={() => navigate('/login')}>
              I have an account
            </button>
          </div>
          <div className="hero-stats">
            {stats.map((stat, i) => (
              <div key={i} className="hero-stat">
                <div className="hero-stat-value">{stat.value}</div>
                <div className="hero-stat-label">{stat.label}</div>
              </div>
            ))}
          </div>
        </div>
        <div className="hero-visual">
          <div className="hero-map-real">
            <div className="hero-map-container" ref={mapRef} />
          </div>
        </div>
      </section>

      {/* Social Proof Bar */}
      <section className="social-proof">
        <div className="social-proof-inner">
          <span>Trusted by travelers tracking their journeys across</span>
          <strong>36 States & UTs</strong>
          <span className="sp-dot" />
          <strong>195+ Countries</strong>
          <span className="sp-dot" />
          <strong>1000+ Destinations</strong>
        </div>
      </section>

      {/* Features Section */}
      <section className="landing-features" id="features">
        <div className="features-header">
          <h2>Everything You Need to<br /><span className="hero-gradient-text">Map Your Adventures</span></h2>
          <p>Powerful features designed for the modern traveler</p>
        </div>
        <div className="features-grid">
          {features.map((f, i) => (
            <div key={i} className="feature-card" style={{ animationDelay: `${i * 0.08}s` }}>
              <div className="feature-icon">{f.icon}</div>
              <h3>{f.title}</h3>
              <p>{f.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* How It Works */}
      <section className="landing-how">
        <div className="how-header">
          <h2>Get Started in <span className="hero-gradient-text">3 Steps</span></h2>
          <p>From signup to your first pin in under a minute</p>
        </div>
        <div className="how-steps">
          <div className="how-step">
            <div className="how-step-num">1</div>
            <h3>Create Free Account</h3>
            <p>Sign up in seconds. No credit card. Your data stays yours.</p>
          </div>
          <div className="how-connector" />
          <div className="how-step">
            <div className="how-step-num">2</div>
            <h3>Mark Visited Places</h3>
            <p>Click states on the India map or countries on the world map to mark them.</p>
          </div>
          <div className="how-connector" />
          <div className="how-step">
            <div className="how-step-num">3</div>
            <h3>Watch Your Story Grow</h3>
            <p>Track progress, unlock milestones, plan trips, and relive your adventures.</p>
          </div>
        </div>
      </section>

      {/* CTA Section */}
      <section className="landing-cta">
        <div className="cta-content">
          <h2>Your Next Adventure Starts Here</h2>
          <p>Join MyTravelGlimpse and turn every trip into a story worth tracking</p>
          <button className="hero-btn-primary cta-btn" onClick={() => navigate('/signup')}>
            Create Free Account <FaArrowRight />
          </button>
        </div>
      </section>

      {/* Footer */}
      <footer className="landing-footer">
        <div className="footer-inner">
          <div className="landing-logo">
            <FaCompass className="landing-logo-icon" />
            <span>MyTravelGlimpse</span>
          </div>
          <p>&copy; {new Date().getFullYear()} MyTravelGlimpse. Built for travelers, by travelers.</p>
        </div>
      </footer>
    </div>
  );
}
